import { isUndefined } from 'lodash-es';

import { ColoredRange } from '../../core/types/colored-range.js';
import { MinMax } from '../../core/types/min-max.js';

const limitIsBetweenRange = (
  from: number,
  allowedMinValue: number,
  to: number,
) => from <= allowedMinValue && allowedMinValue < to;

export const filterColoredRange = (
  coloredRange: ColoredRange[],
  extent: Partial<MinMax> | undefined,
  dataBoundaries?: Partial<MinMax>,
) => {
  if (
    isUndefined(extent) ||
    (isUndefined(extent.min) && isUndefined(extent.max))
  ) {
    return coloredRange;
  }

  const { min, max } = extent;

  const allowedMinValue = min ?? dataBoundaries?.min ?? coloredRange[0].from;
  const allowedMaxValue =
    max ?? dataBoundaries?.max ?? coloredRange[coloredRange.length - 1].to;
  const filteredRange: ColoredRange[] = [];
  coloredRange.forEach((coloredRange) => {
    const { from, to } = coloredRange;
    const isOutOfBounds = from > allowedMaxValue || to < allowedMinValue;
    const minWillCropTheRange = limitIsBetweenRange(from, allowedMinValue, to);
    const maxWillCropTheRange = limitIsBetweenRange(from, allowedMaxValue, to);

    if (isOutOfBounds) {
      return;
    } else if (max && maxWillCropTheRange && min && minWillCropTheRange) {
      filteredRange.push({
        ...coloredRange,
        from: allowedMinValue,
        to: allowedMaxValue,
      });
    } else if (max && maxWillCropTheRange) {
      filteredRange.push({ ...coloredRange, to: allowedMaxValue });
    } else if (min && minWillCropTheRange) {
      filteredRange.push({ ...coloredRange, from: allowedMinValue });
    } else {
      filteredRange.push(coloredRange);
    }
  });
  return filteredRange;
};
